SELECT 
    CAST(COUNT(CASE WHEN Age BETWEEN 13 AND 19 THEN 1 END) AS REAL) * 100 / COUNT(*) AS teenage_percentage
FROM users;

SELECT 
    CAST(COUNT(CASE WHEN Age BETWEEN 13 AND 19 THEN 1 END) AS FLOAT) * 100 / COUNT(*) AS TeenageUserPercentage
FROM users;

SELECT 
    CAST(COUNT(CASE WHEN Age BETWEEN 13 AND 19 THEN 1 END) AS REAL) * 100 / COUNT(*) AS teenage_percentage
FROM users;

SELECT 
    ROUND(COUNT(CASE WHEN Age >= 13 AND Age <= 19 THEN 1 END) * 100.0 / COUNT(*), 2) AS TeenageUserPercentage
FROM users;

SELECT 
    ROUND(CAST(SUM(CASE WHEN Age BETWEEN 13 AND 19 THEN 1 ELSE 0 END) AS REAL) * 100.0 / COUNT(*), 2) AS teenage_percentage
FROM users;

SELECT 
    CAST(COUNT(CASE WHEN Age BETWEEN 13 AND 19 THEN 1 END) AS REAL) * 100 / COUNT(*) AS teenage_percentage
FROM users;

SELECT 
    (COUNT(*) * 1.0 * (SELECT COUNT(*) FROM users WHERE Age BETWEEN 13 AND 19) / COUNT(*)) AS teenage_percentage
FROM users;

SELECT 
    ROUND(COUNT(CASE WHEN Age >= 13 AND Age <= 19 THEN 1 END) * 100.0 / COUNT(*), 2) AS TeenageUserPercentage
FROM users;

